logger = logging.getLogger(__name__)


class RabbitMQConnection:
    """Base class for RabbitMQ connections with retry logic."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'guest',
        password: str = 'guest',
        virtual_host: str = '/',
        heartbeat: int = 600,
        connection_attempts: int = 3,
        retry_delay: int = 5
    ):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.virtual_host = virtual_host
        self.heartbeat = heartbeat
        self.connection_attempts = connection_attempts
        self.retry_delay = retry_delay
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.channel.Channel] = None

    def connect(self):
        """Establish connection to RabbitMQ with retry logic."""
        credentials = pika.PlainCredentials(self.username, self.password)
        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            heartbeat=self.heartbeat,
            connection_attempts=self.connection_attempts,
            retry_delay=self.retry_delay
        )

        for attempt in range(1, self.connection_attempts + 1):
            try:
                logger.info(f"Attempting to connect to RabbitMQ (attempt {attempt}/{self.connection_attempts})...")
                self.connection = pika.BlockingConnection(parameters)
                self.channel = self.connection.channel()
                logger.info("Successfully connected to RabbitMQ.")
                return
            except pika.exceptions.AMQPConnectionError as e:
                logger.error(f"Connection attempt {attempt} failed: {e}")
                if attempt < self.connection_attempts:
                    logger.info(f"Retrying in {self.retry_delay} seconds...")
                    time.sleep(self.retry_delay)
                else:
                    raise ConnectionError(
                        f"Failed to connect to RabbitMQ after {self.connection_attempts} attempts."
                    ) from e

    def close(self):
        """Close the RabbitMQ connection."""
        if self.connection and not self.connection.is_closed:
            try:
                self.connection.close()
                logger.info("RabbitMQ connection closed.")
            except Exception as e:
                logger.error(f"Error closing connection: {e}")

    def ensure_connection(self):
        """Ensure the connection is active, reconnect if necessary."""
        if self.connection is None or self.connection.is_closed:
            self.connect()
        if self.channel is None or self.channel.is_closed:
            self.channel = self.connection.channel()


class TaskPublisher(RabbitMQConnection):
    """Publishes task messages to RabbitMQ queues."""

    def __init__(
        self,
        queue_name: str = 'task_queue',
        exchange_name: str = '',
        exchange_type: str = 'direct',
        durable: bool = True,
        **kwargs
    ):
        super().__init__(**kwargs)
        self.queue_name = queue_name
        self.exchange_name = exchange_name
        self.exchange_type = exchange_type
        self.durable = durable

    def setup(self):
        """Set up the exchange and queue."""
        self.ensure_connection()

        if self.exchange_name:
            self.channel.exchange_declare(
                exchange=self.exchange_name,
                exchange_type=self.exchange_type,
                durable=self.durable
            )

        self.channel.queue_declare(
            queue=self.queue_name,
            durable=self.durable,
            arguments={
                'x-message-ttl': 86400000,  # 24 hours TTL
                'x-max-length': 100000,
                'x-dead-letter-exchange': 'dlx_exchange',
                'x-dead-letter-routing-key': 'dlx_routing_key'
            }
        )

        # Set up dead letter exchange and queue
        self.channel.exchange_declare(
            exchange='dlx_exchange',
            exchange_type='direct',
            durable=True
        )
        self.channel.queue_declare(
            queue='dead_letter_queue',
            durable=True
        )
        self.channel.queue_bind(
            queue='dead_letter_queue',
            exchange='dlx_exchange',
            routing_key='dlx_routing_key'
        )

        if self.exchange_name:
            self.channel.queue_bind(
                queue=self.queue_name,
                exchange=self.exchange_name,
                routing_key=self.queue_name
            )

        logger.info(f"Publisher setup complete for queue '{self.queue_name}'.")

    def publish_task(
        self,
        task_name: str,
        task_data: Dict[str, Any],
        priority: int = 0,
        correlation_id: Optional[str] = None,
        reply_to: Optional[str] = None
    ) -> str:
        """Publish a task message to the queue."""
        self.ensure_connection()

        task_id = correlation_id or str(uuid.uuid4())
        message = {
            'task_id': task_id,
            'task_name': task_name,
            'task_data': task_data,
            'created_at': datetime.utcnow().isoformat(),
            'priority': priority,
            'retry_count': 0,
            'max_retries': 3
        }

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent message
            content_type='application/json',
            correlation_id=task_id,
            priority=priority,
            timestamp=int(time.time()),
            headers={
                'task_name': task_name,
                'created_at': datetime.utcnow().isoformat()
            }
        )

        if reply_to:
            properties.reply_to = reply_to

        routing_key = self.queue_name

        try:
            self.channel.basic_publish(
                exchange=self.exchange_name,
                routing_key=routing_key,
                body=json.dumps(message),
                properties=properties,
                mandatory=True
            )
            logger.info(f"Published task '{task_name}' with ID '{task_id}' to queue '{self.queue_name}'.")
            return task_id
        except pika.exceptions.UnroutableError:
            logger.error(f"Message for task '{task_name}' was unroutable.")
            raise
        except Exception as e:
            logger.error(f"Failed to publish task '{task_name}': {e}")
            raise

    def publish_batch(self, tasks: list) -> list:
        """Publish multiple tasks in batch."""
        task_ids = []
        for task in tasks:
            task_id = self.publish_task(
                task_name=task.get('task_name'),
                task_data=task.get('task_data', {}),
                priority=task.get('priority', 0)
            )
            task_ids.append(task_id)
        logger.info(f"Published batch of {len(task_ids)} tasks.")
        return task_ids


class TaskConsumer(RabbitMQConnection):
    """Consumes and processes task messages from RabbitMQ queues."""

    def __init__(
        self,
        queue_name: str = 'task_queue',
        prefetch_count: int = 1,
        durable: bool = True,
        auto_ack: bool = False,
        **kwargs
    ):
        super().__init__(**kwargs)
        self.queue_name = queue_name
        self.prefetch_count = prefetch_count
        self.durable = durable
        self.auto_ack = auto_ack
        self.task_handlers: Dict[str, Callable] = {}
        self._consuming = False

    def setup(self):
        """Set up the consumer queue and QoS."""
        self.ensure_connection()

        self.channel.queue_declare(
            queue=self.queue_name,
            durable=self.durable,
            arguments={
                'x-message-ttl': 86400000,
                'x-max-length': 100000,
                'x-dead-letter-exchange': 'dlx_exchange',
                'x-dead-letter-routing-key': 'dlx_routing_key'
            }
        )

        # Set QoS - prefetch count controls how many messages
        # are dispatched to the consumer before acknowledgment
        self.channel.basic_qos(prefetch_count=self.prefetch_count)

        logger.info(f"Consumer setup complete for queue '{self.queue_name}' "
                     f"with prefetch_count={self.prefetch_count}.")

    def register_handler(self, task_name: str, handler: Callable):
        """Register a handler function for a specific task type."""
        self.task_handlers[task_name] = handler
        logger.info(f"Registered handler for task '{task_name}'.")

    def _on_message(self, channel, method, properties, body):
        """Callback for processing received messages."""
        try:
            message = json.loads(body)
            task_id = message.get('task_id', 'unknown')
            task_name = message.get('task_name', 'unknown')
            task_data = message.get('task_data', {})
            retry_count = message.get('retry_count', 0)
            max_retries = message.get('max_retries', 3)

            logger.info(f"Received task '{task_name}' with ID '{task_id}' "
                        f"(retry: {retry_count}/{max_retries}).")

            handler = self.task_handlers.get(task_name)

            if handler is None:
                logger.warning(f"No handler registered for task '{task_name}'. "
                               f"Rejecting message.")
                if not self.auto_ack:
                    channel.basic_nack(
                        delivery_tag=method.delivery_tag,
                        requeue=False
                    )
                return

            # Execute the task handler
            start_time = time.time()
            result = handler(task_id=task_id, task_data=task_data)
            elapsed = time.time() - start_time

            logger.info(f"Task '{task_name}' (ID: {task_id}) completed in {elapsed:.3f}s. "
                        f"Result: {result}")

            # Acknowledge the message
            if not self.auto_ack:
                channel.basic_ack(delivery_tag=method.delivery_tag)

            # If there's a reply_to queue, send the result back
            if properties.reply_to:
                response = {
                    'task_id': task_id,
                    'task_name': task_name,
                    'result': result,
                    'status': 'completed',
                    'elapsed_time': elapsed,
                    'completed_at': datetime.utcnow().isoformat()
                }
                channel.basic_publish(
                    exchange='',
                    routing_key=properties.reply_to,
                    body=json.dumps(response),
                    properties=pika.BasicProperties(
                        correlation_id=properties.correlation_id,
                        content_type='application/json'
                    )
                )

        except json.JSONDecodeError as e:
            logger.error(f"Failed to decode message body: {e}")
            if not self.auto_ack:
                channel.basic_nack(
                    delivery_tag=method.delivery_tag,
                    requeue=False
                )

        except Exception as e:
            logger.error(f"Error processing task: {e}", exc_info=True)

            # Retry logic
            try:
                message = json.loads(body)
                retry_count = message.get('retry_count', 0)
                max_retries = message.get('max_retries', 3)

                if retry_count < max_retries:
                    message['retry_count'] = retry_count + 1
                    message['last_error'] = str(e)
                    message['retried_at'] = datetime.utcnow().isoformat()

                    # Re-publish with incremented retry count
                    channel.basic_publish(
                        exchange='',
                        routing_key=self.queue_name,
                        body=json.dumps(message),
                        properties=pika.BasicProperties(
                            delivery_mode=2,
                            content_type='application/json',
                            correlation_id=message.get('task_id')
                        )
                    )
                    logger.info(f"Task '{message.get('task_name')}' requeued "
                                f"(retry {message['retry_count']}/{max_retries}).")
                else:
                    logger.error(f"Task '{message.get('task_name')}' exceeded max retries. "
                                 f"Sending to dead letter queue.")
            except Exception as retry_error:
                logger.error(f"Failed to handle retry: {retry_error}")

            if not self.auto_ack:
                channel.basic_nack(
                    delivery_tag=method.delivery_tag,
                    requeue=False
                )

    def start_consuming(self):
        """Start consuming messages from the queue."""
        self.ensure_connection()
        self._consuming = True

        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self._on_message,
            auto_ack=self.auto_ack
        )

        logger.info(f"Consumer started. Waiting for messages on queue '{self.queue_name}'...")

        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user.")
            self.stop_consuming()
        except Exception as e:
            logger.error(f"Consumer error: {e}")
            self.stop_consuming()
            raise

    def stop_consuming(self):
        """Stop consuming messages."""
        self._consuming = False
        if self.channel and self.channel.is_open:
            self.channel.stop_consuming()
            logger.info("Consumer stopped.")
        self.close()


